DROP TABLE IF EXISTS ste_vec;
CREATE TABLE ste_vec
(
    id bigint,
    e eql_v2_encrypted,
    PRIMARY KEY(id)
);

-- Inlined v2.3-shape ste_vec records (10 records, ids 1-10).
--
-- Plaintext shape (for reference):
--   { "hello": "world {N}", "number": N,
--     "nested": { "number": <fixed>, "hello": "world {N}" } }
--
-- Changes from the pre-2.3 fixture:
--   - Root-level `c` field removed (invalid on SteVecPayload per the
--     v2.3 schema; root SteVecPayload is `{i, v, sv}`).
--   - Each sv entry now carries `hm`. For entries that previously had
--     `b3` (Blake3) it's renamed to `hm` with the same bytes; for
--     `oc`-bearing entries (ordered terms), `hm` is synthesised as
--     `md5(s || record_id)` — opaque to callers; what matters is
--     per-record equality semantics for ste_vec_contains.
--   - The `oc` ciphertexts are kept verbatim from the pre-2.3 fixture
--     — they're real cipherstash-suite CLLW output whose byte
--     structure satisfies the `compare_ore_cllw_term` rotation rule.
--
-- Selectors (path -> column-name HMAC):
--   $                  -> 9493d6010fe7845d52149b697729c745
--   $.hello            -> d90b97b5207d30fe867ca816ed0fe4a7
--   $.nested           -> 3a9a5d5601369d00a92e851b5490d2d1
--   $.nested.hello     -> f3b937817818610f955b6bbbc337aa2b
--   $.number           -> fa6f99753674e2e0db242dd805eacac8
--   $.nested.number    -> 3dba004f4d7823446e7cb71f6681b344
--
-- `tests/test_helpers.sql` also exposes `build_synthetic_ste_vec(id)`
-- which returns the same row for a given id (use it in test code that
-- needs to generate a fresh row dynamically).

